internal static bool IsValidChannel(string value)
    {
        if (value is PackageChannelNames.Stable or PackageChannelNames.Staging or PackageChannelNames.Daily or PackageChannelNames.Local)
        {
            return true;
        }

        if (!value.StartsWith(PrChannelPrefix, StringComparison.Ordinal))
        {
            return false;
        }

        // Reject "pr-" with no suffix and "pr-<non-ASCII-digit-run>". MemoryExtensions
        // .ContainsAnyExceptInRange is AOT-safe and matches the ASCII-only contract
        // the build pipeline emits (never localized digits, never sign chars).
        var digits = value.AsSpan(PrChannelPrefix.Length);
        return !digits.IsEmpty && !digits.ContainsAnyExceptInRange('0', '9');
    }

public InstallationDiscovery(
    IIdentityChannelReader channelReader,
    IInstallSidecarReader sidecarReader,
    IPeerInstallProbe peerProbe,
    CliExecutionContext executionContext,
    ILogger<InstallationDiscovery> logger,
    IEnumerable<IInstallationCandidateSource>? candidateSources = null)
{
    ArgumentNullException.ThrowIfNull(channelReader);
    ArgumentNullException.ThrowIfNull(sidecarReader);
    ArgumentNullException.ThrowIfNull(peerProbe);
    ArgumentNullException.ThrowIfNull(executionContext);
    ArgumentNullException.ThrowIfNull(logger);

    _channelReader = channelReader;
    _sidecarReader = sidecarReader;
    _peerProbe = peerProbe;
    _executionContext = executionContext;
    _logger = logger;
    var sources = candidateSources?.ToArray();
    _candidateSources = sources is { Length: > 0 } ? sources : CreateDefaultCandidateSources();
}

private static string GetPathStatus(string? canonicalPath, IEnumerable<InstallationPathHit> pathHits)
    {
        if (string.IsNullOrEmpty(canonicalPath))
        {
            return InstallationPathStatus.NotOnPath;
        }

        var comparer = OperatingSystem.IsWindows() ? StringComparer.OrdinalIgnoreCase : StringComparer.Ordinal;
        var isFirst = true;
        foreach (var pathHit in pathHits)
        {
            if (comparer.Equals(pathHit.CanonicalPath, canonicalPath))
            {
                return isFirst ? InstallationPathStatus.Active : InstallationPathStatus.Shadowed;
            }

            isFirst = false;
        }

        return InstallationPathStatus.NotOnPath;
    }

public void Run(string binaryDir)
    {
        if (string.IsNullOrEmpty(binaryDir))
        {
            return;
        }

        var sidecarPath = Path.Combine(binaryDir, InstallSidecarReader.SidecarFileName);
        if (File.Exists(sidecarPath))
        {
            return;
        }

        var processPath = Environment.ProcessPath;
        if (string.IsNullOrEmpty(processPath))
        {
            return;
        }

        if (!_registry.HasWingetAspireUninstallEntry(processPath))
        {
            return;
        }

        TryWriteSidecarAtomically(binaryDir, sidecarPath);
    }

private static bool SatisfiesComparator(SemVersion version, string comparator)
    {
        var (op, operandText) = ParseComparator(comparator);
        var operand = ParseCompatibilityVersion(operandText);
        var comparison = SemVersion.ComparePrecedence(version, operand);

        return op switch
        {
            ">" => comparison > 0,
            ">=" => comparison >= 0,
            "<" => comparison < 0,
            "<=" => comparison <= 0,
            "=" or "==" => comparison == 0,
            _ => throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Unsupported Aspire skills bundle version comparator '{0}'.", op))
        };
    }

private static (string Operator, string Operand) ParseComparator(string comparator)
    {
        foreach (var op in new[] { ">=", "<=", "==", ">", "<", "=" })
        {
            if (comparator.StartsWith(op, StringComparison.Ordinal))
            {
                var operand = comparator[op.Length..];
                if (string.IsNullOrWhiteSpace(operand))
                {
                    throw new InvalidOperationException(string.Format(CultureInfo.InvariantCulture, "Aspire skills bundle contains an invalid version comparator '{0}'.", comparator));
                }

                return (op, operand);
            }
        }

        return ("=", comparator);
    }

private static void ValidateArchiveSha256(string archivePath, string expectedSha256)
    {
        var expectedHash = AspireSkillsBundle.NormalizeSha256(expectedSha256);
        string actualHash;
        using (var stream = File.OpenRead(archivePath))
        {
            actualHash = Convert.ToHexString(SHA256.HashData(stream)).ToLowerInvariant();
        }

        if (!string.Equals(expectedHash, actualHash, StringComparison.OrdinalIgnoreCase))
        {
            throw new InvalidOperationException(string.Format(
                CultureInfo.CurrentCulture,
                AgentCommandStrings.AspireSkillsInstaller_ArchiveHashVerificationFailed,
                expectedHash,
                actualHash));
        }
    }

private static async Task<FileStream> AcquireCacheLockAsync(string cacheRoot, string version, CancellationToken cancellationToken)
    {
        var lockPath = Path.Combine(cacheRoot, $".{GetSafeFileName(version)}.lock");
        while (true)
        {
            try
            {
                return new FileStream(
                    lockPath,
                    FileMode.OpenOrCreate,
                    FileAccess.ReadWrite,
                    FileShare.None,
                    bufferSize: 1,
                    FileOptions.Asynchronous | FileOptions.DeleteOnClose);
            }
            catch (IOException) when (!cancellationToken.IsCancellationRequested)
            {
                await Task.Delay(TimeSpan.FromMilliseconds(100), cancellationToken).ConfigureAwait(false);
            }
        }
    }

private static bool HasAspireServerConfigured(DirectoryInfo repoRoot)
    {
        var configFilePath = Path.Combine(repoRoot.FullName, McpConfigFileName);

        if (!File.Exists(configFilePath))
        {
            return false;
        }

        try
        {
            var content = File.ReadAllText(configFilePath);
            var config = JsonNode.Parse(content)?.AsObject();

            if (config is null)
            {
                return false;
            }

            if (config.TryGetPropertyValue("mcpServers", out var serversNode) && serversNode is JsonObject servers)
            {
                return servers.ContainsKey(AspireServerName);
            }

            return false;
        }
        catch (JsonException)
        {
            // If the JSON is malformed, assume aspire is not configured
            return false;
        }
    }

